<?php
declare(strict_types=1);require dirname(__DIR__).'/app/core/Env.php';\App\Core\Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function(string $class):void{$prefix='App\\';if(!str_starts_with($class,$prefix))return;$relative=substr($class,strlen($prefix));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$file=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($file))require_once $file;});$composer=dirname(__DIR__).'/vendor/autoload.php';if(is_file($composer))require_once $composer;
use App\Core\Database;use App\Core\Env;use App\Services\EmailService;use App\Services\TeamsService;
$pdo=Database::connection();$rows=$pdo->query("SELECT a.*,u.email assigned_email,u.name assigned_name,j.job_number FROM corrective_actions a LEFT JOIN users u ON u.id=a.assigned_user_id LEFT JOIN jobs j ON j.id=a.job_id WHERE a.status NOT IN ('verified','closed') AND a.due_at IS NOT NULL AND a.due_at<=DATE_ADD(NOW(),INTERVAL 2 DAY)")->fetchAll();$mail=new EmailService();$teams=new TeamsService();$app=rtrim((string)Env::get('APP_URL',''),'/');foreach($rows as $a){$overdue=strtotime((string)$a['due_at'])<time();$level=$overdue?min(3,max(1,(int)floor((time()-strtotime((string)$a['due_at']))/86400)+1)):0;$should=empty($a['last_notified_at'])||strtotime((string)$a['last_notified_at'])<time()-86400;if(!$should)continue;$subject=($overdue?'Overdue':'Due soon').' corrective action: '.$a['title'];$body='<p>'.htmlspecialchars($a['assigned_name']?:'Team').',</p><p>'.htmlspecialchars($a['title']).' is '.($overdue?'overdue':'due soon').'.</p><p>Due: '.htmlspecialchars((string)$a['due_at']).'</p><p><a href="'.$app.'/portal/corrective-actions">Open corrective actions</a></p>';try{if($mail->configured()&&!empty($a['assigned_email']))$mail->sendMail($a['assigned_email'],$subject,$body);if($teams->configured()&&($overdue||$a['severity']==='critical'))$teams->send($subject,strip_tags($a['description']??''),$app.'/portal/corrective-actions');$pdo->prepare('UPDATE corrective_actions SET escalation_level=GREATEST(escalation_level,?),last_notified_at=NOW(),escalated_at=IF(? > escalation_level,NOW(),escalated_at) WHERE id=?')->execute([$level,$level,$a['id']]);$pdo->prepare("INSERT INTO corrective_action_events(corrective_action_id,event_type,message,metadata_json) VALUES(?,'notification_sent',?,?)")->execute([$a['id'],$subject,json_encode(['level'=>$level,'overdue'=>$overdue])]);echo "Processed #{$a['id']}\n";}catch(Throwable $e){fwrite(STDERR,"#{$a['id']}: {$e->getMessage()}\n");}}
